// Əsas tiplər
let name: string = 'Ali';
let age: number = 25;
let isStudent: boolean = true;
let numbers: number[] = [1, 2, 3];
let person: object = { name: 'Vəli', age: 30 };
let anything: any = 'Hər şey ola bilər';
let unknownValue: unknown = 42;

function logMessage(): void {
  console.log('Mesaj yazıldı');
}

function throwError(): never {
  throw new Error('Xəta!');
}

console.log(name, age, isStudent, numbers, person);
logMessage();

// Tip inferensi
let name = 'Ayşə'; // TypeScript avtomatik olaraq string tipi təyin edir
let age = 30; // number tipi
// name = 42; // Xəta: number string-ə təyin edilə bilməz

console.log(name, age);

// Funksiya tipləri
function add(a: number, b: number): number {
  return a + b;
}

console.log(add(5, 3)); // 8
// console.log(add('5', 3)); // Xəta: string number gözlənilir

// Tip aliası
type Point = {
  x: number;
  y: number;
};

let point: Point = { x: 10, y: 20 };
console.log(point); // { x: 10, y: 20 }

// Birləşmə tipləri
let id: string | number;
id = 'ABC123';
console.log(id); // ABC123
id = 123;
console.log(id); // 123
// id = true; // Xəta: boolean birləşmə tipinə uyğun deyil

// Kəsişmə tipləri
type Person = { name: string };
type Employee = { id: number };

type Staff = Person & Employee;

let staff: Staff = { name: 'Fatma', id: 101 };
console.log(staff); // { name: 'Fatma', id: 101 }

// Literal tiplər
type Direction = 'up' | 'down' | 'left' | 'right';
let move: Direction = 'up';
console.log(move); // up
// move = 'diagonal'; // Xəta: 'diagonal' Direction tipinə uyğun deyil

// Nullable tiplər
let value: string | null = 'Hello';
value = null;
console.log(value); // null
// value = 42; // Xəta: number nullable tipə uyğun deyil

// Obyektlərdə tip annotasiyası
interface User {
  name: string;
  age: number;
  email?: string; // Opsional xassə
}

let user: User = {
  name: 'Məmməd',
  age: 22,
};

console.log(user); // { name: 'Məmməd', age: 22 }

// Təhlükəsizlik nümunəsi
let data: unknown = 'Hello';
// console.log(data.toUpperCase()); // Xəta: unknown tipinə metod tətbiq edilə bilməz
if (typeof data === 'string') {
  console.log(data.toUpperCase()); // HELLO
}

// Səhvə yol açan nümunə
let value: any = 'Hello';
console.log(value.toUpperCase()); // HELLO
value = 42;
// console.log(value.toUpperCase()); // Runtime xətası

// Düzgün yol
let text: string = 'Hello';
console.log(text.toUpperCase()); // HELLO

