// Core types
let name: string = 'Alice';
let age: number = 25;
let isStudent: boolean = true;
let numbers: number[] = [1, 2, 3];
let person: object = { name: 'Bob', age: 30 };
let anything: any = 'Anything goes';
let unknownValue: unknown = 42;

function logMessage(): void {
  console.log('Message logged');
}

function throwError(): never {
  throw new Error('Error!');
}

console.log(name, age, isStudent, numbers, person);
logMessage();

// Type inference
let name = 'Eve'; // TypeScript infers string type
let age = 30; // number type
// name = 42; // Error: number cannot be assigned to string

console.log(name, age);

// Function types
function add(a: number, b: number): number {
  return a + b;
}

console.log(add(5, 3)); // 8
// console.log(add('5', 3)); // Error: string not expected

// Type alias
type Point = {
  x: number;
  y: number;
};

let point: Point = { x: 10, y: 20 };
console.log(point); // { x: 10, y: 20 }

// Union types
let id: string | number;
id = 'ABC123';
console.log(id); // ABC123
id = 123;
console.log(id); // 123
// id = true; // Error: boolean is not part of union type

// Intersection types
type Person = { name: string };
type Employee = { id: number };

type Staff = Person & Employee;

let staff: Staff = { name: 'Grace', id: 101 };
console.log(staff); // { name: 'Grace', id: 101 }

// Literal types
type Direction = 'up' | 'down' | 'left' | 'right';
let move: Direction = 'up';
console.log(move); // up
// move = 'diagonal'; // Error: 'diagonal' is not a valid Direction

// Nullable types
let value: string | null = 'Hello';
value = null;
console.log(value); // null
// value = 42; // Error: number is not part of nullable type

// Type annotations with objects
interface User {
  name: string;
  age: number;
  email?: string; // Optional property
}

let user: User = {
  name: 'John',
  age: 22,
};

console.log(user); // { name: 'John', age: 22 }

// Security example
let data: unknown = 'Hello';
// console.log(data.toUpperCase()); // Error: cannot call method on unknown
if (typeof data === 'string') {
  console.log(data.toUpperCase()); // HELLO
}

// Error-prone example
let value: any = 'Hello';
console.log(value.toUpperCase()); // HELLO
value = 42;
// console.log(value.toUpperCase()); // Runtime error

// Correct approach
let text: string = 'Hello';
console.log(text.toUpperCase()); // HELLO

