// Основные типы
let name: string = 'Алиса';
let age: number = 25;
let isStudent: boolean = true;
let numbers: number[] = [1, 2, 3];
let person: object = { name: 'Боб', age: 30 };
let anything: any = 'Может быть чем угодно';
let unknownValue: unknown = 42;

function logMessage(): void {
  console.log('Сообщение записано');
}

function throwError(): never {
  throw new Error('Ошибка!');
}

console.log(name, age, isStudent, numbers, person);
logMessage();

// Вывод типов
let name = 'Ева'; // TypeScript автоматически определяет тип string
let age = 30; // тип number
// name = 42; // Ошибка: number не может быть присвоен string

console.log(name, age);

// Типы функций
function add(a: number, b: number): number {
  return a + b;
}

console.log(add(5, 3)); // 8
// console.log(add('5', 3)); // Ошибка: ожидается number

// Псевдоним типа
type Point = {
  x: number;
  y: number;
};

let point: Point = { x: 10, y: 20 };
console.log(point); // { x: 10, y: 20 }

// Объединения типов
let id: string | number;
id = 'ABC123';
console.log(id); // ABC123
id = 123;
console.log(id); // 123
// id = true; // Ошибка: boolean не входит в объединение типов

// Пересечения типов
type Person = { name: string };
type Employee = { id: number };

type Staff = Person & Employee;

let staff: Staff = { name: 'Грейс', id: 101 };
console.log(staff); // { name: 'Грейс', id: 101 }

// Литеральные типы
type Direction = 'up' | 'down' | 'left' | 'right';
let move: Direction = 'up';
console.log(move); // up
// move = 'diagonal'; // Ошибка: 'diagonal' не является допустимым значением Direction

// Nullable-типы
let value: string | null = 'Привет';
value = null;
console.log(value); // null
// value = 42; // Ошибка: number не входит в nullable-тип

// Аннотации типов для объектов
interface User {
  name: string;
  age: number;
  email?: string; // Опциональное свойство
}

let user: User = {
  name: 'Джон',
  age: 22,
};

console.log(user); // { name: 'Джон', age: 22 }

// Пример безопасности
let data: unknown = 'Привет';
// console.log(data.toUpperCase()); // Ошибка: метод нельзя вызвать на unknown
if (typeof data === 'string') {
  console.log(data.toUpperCase()); // ПРИВЕТ
}

// Пример, вызывающий ошибку
let value: any = 'Привет';
console.log(value.toUpperCase()); // ПРИВЕТ
value = 42;
// console.log(value.toUpperCase()); // Ошибка во время выполнения

// Правильный подход
let text: string = 'Привет';
console.log(text.toUpperCase()); // ПРИВЕТ

